/**
 * nugget-memory.js — service-worker entry point for the WebNugget memory layer.
 *
 * Bridges the @browser-memex/core memory layer (NuggetStore) to the rest of
 * the service-worker code. Reuses the live NuggetStore booted by
 * extension-services.js so we don't open the SQLite DB twice.
 *
 * Single capture surface (`captureFact`) enforces the active profile's
 * privacy policy before any write:
 *   - `memoryEnabled === false`  → drop the fact silently
 *   - URL host ∈ `disabledDomains` (or subdomain) → drop
 *   - URL is internal (chrome://, about://, file://, …) → drop
 *   - Credentials in URL (user:pass@) → redact before storage
 *
 * Reads (`queryFacts`, `getFact`, `countFacts`) are profile-scoped via the
 * active profile id from extension-services.
 *
 * See:
 *   - ADR 0005 (NuggetIndex memory layer)
 *   - docs/dev/memory-architecture.md
 */

import { inferValidity } from "@browser-memex/core/memory";
import {
  services,
  activeProfileId,
  isBooted,
  bootProfiles,
} from "./extension-services.js";

/** Async wait for the heavy SQLite boot, with a timeout that fails open
 *  (returns null) so calls during early startup don't hang the agent loop. */
async function getNuggetStore(timeoutMs = 5000) {
  if (isBooted()) return services().nuggetStore;
  const start = Date.now();
  while (!isBooted() && Date.now() - start < timeoutMs) {
    await new Promise((r) => setTimeout(r, 100));
  }
  if (!isBooted()) return null;
  return services().nuggetStore;
}

/** Load the active profile's privacy settings. Falls back to "capture
 *  everything" if the profile store is empty (should never happen). */
async function getActivePrivacy() {
  try {
    const { profileStore } = await bootProfiles();
    const profile = await profileStore.getActive(Date.now());
    return profile?.privacy ?? { memoryEnabled: true, disabledDomains: [] };
  } catch {
    return { memoryEnabled: true, disabledDomains: [] };
  }
}

/** Host check that also matches subdomains. Empty list → no match. */
function isHostBlocked(hostname, disabledDomains) {
  if (!Array.isArray(disabledDomains) || disabledDomains.length === 0) return false;
  const lower = String(hostname || "").toLowerCase();
  return disabledDomains.some((d) => {
    const dd = String(d || "").toLowerCase();
    if (!dd) return false;
    return lower === dd || lower.endsWith(`.${dd}`);
  });
}

/** Returns true for chrome:// / chrome-extension:// / about: / file: etc.
 *  Internal URLs are never captured — they're either extension UI or local
 *  files, both of which are out of scope for the cross-agent memex. */
function isInternalUrl(url) {
  try {
    const u = new URL(url);
    return ![
      "http:",
      "https:",
      "ftp:",
    ].includes(u.protocol);
  } catch {
    return true;
  }
}

/** Strip user:pass@ from a URL. Returns the URL string unchanged on failure. */
function redactCredentials(url) {
  try {
    const u = new URL(url);
    if (u.username || u.password) {
      u.username = "";
      u.password = "";
    }
    return u.toString();
  } catch {
    return url;
  }
}

/**
 * Insert a freshly extracted nugget. Enforces the active profile's privacy
 * policy + redacts credentials. Returns `{ outcome, nuggetId }` on success,
 * `{ dropped: <reason> }` if blocked, or null if the memory layer isn't
 * available yet.
 *
 * Required: extraction.fact, extraction.sourceUrl, extraction.agentId.
 */
export async function captureFact(extraction) {
  if (!extraction?.fact || !extraction?.sourceUrl) {
    return { dropped: "missing fact or sourceUrl" };
  }

  const privacy = await getActivePrivacy();
  if (privacy?.memoryEnabled === false) {
    return { dropped: "memory disabled for active profile" };
  }
  if (isInternalUrl(extraction.sourceUrl)) {
    return { dropped: "internal URL" };
  }

  let host;
  try {
    host = new URL(extraction.sourceUrl).hostname;
  } catch {
    return { dropped: "unparseable URL" };
  }
  if (isHostBlocked(host, privacy?.disabledDomains)) {
    return { dropped: `host blocked: ${host}` };
  }

  const safeUrl = redactCredentials(extraction.sourceUrl);

  const store = await getNuggetStore();
  if (!store) return null;

  const extractedAt = extraction.extractedAt ?? Date.now();
  const validity = inferValidity({
    extractedAt,
    sourceUrl: safeUrl,
    uiSignals: extraction.uiSignals ?? [],
  });
  validity.scope = extraction.scope ?? `host:${host}`;

  const candidate = {
    kind: extraction.kind ?? "SemanticFact",
    fact: extraction.fact,
    canonicalText:
      extraction.canonicalText ??
      `${extraction.fact.subject} ${extraction.fact.predicate} ${extraction.fact.object}`,
    validity,
    provenance: [
      {
        sourceUrl: safeUrl,
        domElementRef: extraction.domElementRef ?? null,
        pageTitle: extraction.pageTitle ?? null,
        screenshotHash: extraction.screenshotHash ?? null,
        extractedAt,
        extractionSessionId: extraction.extractionSessionId ?? null,
        agentId: extraction.agentId,
      },
    ],
    createdAt: Date.now(),
    tier: extraction.tier ?? "profile",
    ownerSessionId: extraction.extractionSessionId ?? null,
    ownerAgentId: extraction.agentId,
  };

  try {
    return store.insert(candidate, activeProfileId());
  } catch (e) {
    return { dropped: `insert failed: ${e?.message ?? e}` };
  }
}

/**
 * Convenience: record that an agent task completed at a given URL. Generates
 * a SemanticFact of the form (url, "task_completed", taskTitle) so the next
 * time someone asks "did I do X on Y?" the memex has an answer.
 */
export async function captureTaskCompletion({ taskTitle, sourceUrl, agentId, sessionId }) {
  if (!sourceUrl || !taskTitle) return { dropped: "missing fields" };
  return captureFact({
    kind: "SemanticFact",
    fact: {
      subject: sourceUrl,
      predicate: "task_completed",
      object: taskTitle,
    },
    sourceUrl,
    extractedAt: Date.now(),
    agentId: agentId ?? "browser-memex",
    extractionSessionId: sessionId ?? null,
  });
}

/** Query the memory layer, scoped to the active profile. */
export async function queryFacts(text, options = {}) {
  const store = await getNuggetStore();
  if (!store) return [];
  return store.query(text, { ...options, profileId: activeProfileId() });
}

export async function getFact(id) {
  const store = await getNuggetStore();
  if (!store) return null;
  return store.get(id);
}

export async function countFacts() {
  const store = await getNuggetStore();
  if (!store) return 0;
  return store.count(activeProfileId());
}

/** Legacy alias kept for any callers that still import insertFact. */
export const insertFact = captureFact;
